Here are the MSTest comparison assertions you need and a complete test class:

**Key assertions for boundary checking:**

| Assertion | Purpose |
|---|---|
| `Assert.IsGreaterThan(lowerBound, actual)` | Value exceeds a bound |
| `Assert.IsLessThan(upperBound, actual)` | Value is below a bound |
| `Assert.IsInRange(actual, low, high)` | Value falls within a range |
| `Assert.ThrowsExactly<T>(action)` | Invalid input throws |

Here's the test class:

```csharp
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator;

    public ScoreCalculatorTests()
    {
        _calculator = new ScoreCalculator();
    }

    // --- CalculatePercentage ---

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    [DataRow(1, 3, 33.333333333333336)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_Result_IsInValidRange()
    {
        var result = _calculator.CalculatePercentage(7, 10);

        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade ---

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(100.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.9, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.9, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(double percentage, string expected)
    {
        var result = _calculator.GetGrade(percentage);

        Assert.AreEqual(expected, result);
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_PartialScore_ReturnsNormalizedValue()
    {
        var result = _calculator.NormalizeScore(75.0, 150.0);

        Assert.AreEqual(50.0, result);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        var result = _calculator.NormalizeScore(200.0, 100.0);

        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_Zero_ReturnsZero()
    {
        var result = _calculator.NormalizeScore(0.0, 100.0);

        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, 0.0));
    }
}
```

**Key patterns used:**

- **`Assert.IsInRange(actual, low, high)`** — verifies percentage/normalized values stay in `[0, 100]`
- **`Assert.IsGreaterThan(lowerBound, actual)`** — confirms value strictly exceeds a bound
- **`Assert.IsLessThan(upperBound, actual)`** — confirms value is strictly below a bound
- **`Assert.ThrowsExactly<T>`** — validates guard clauses throw the exact exception type
- **`[DataRow]` at boundaries** (90, 89.9, 80, 79.9…) — tests grade cutoff edges precisely

These comparison assertions are available in MSTest 3.x+ and give much clearer failure messages than `Assert.IsTrue(result > 0)`.
